INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (65, 'Marsch der priester', '', 'die_zauberflöte/Mozart-Die_Zauberflöte-10-Marsch_der_priester.pdf', 'intermezzo', 10, 66, 64, 10);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (66, 'O Isis und Osiris', 'After a solemn March, Sarastro tells the other priests that Tamino is ready to undergo the trials of enlightenment. In this aria he invokes Isis and Osiris, the ancient gods, and asks them to protect Tamino and Pamina.', 'die_zauberflöte/Mozart-Die_Zauberflöte-11-O_Isis_und_Osiris.pdf', 'aria', 11, 67, 65, 10);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (67, 'Bewahret euch vor Weibertücken', '', 'die_zauberflöte/Mozart-Die_Zauberflöte-12-Bewahret_euch_vor_Weibertücken.pdf', 'duet', 12, 68, 66, 10);
