INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (69, 'Der Hölle Rache kocht in meinem Herzen', 'The queen of the night gives Pamina a dagger and tells her to kill Sarastro. ', 'die_zauberflöte/Mozart-Die_Zauberflöte-14-Der_Hölle_Rache_kocht_in_meinem_Herzen.pdf', 'aria', 14, 70, 68, 10);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (70, 'In diesen heilgen Hallen', 'Pamina begs Sarastro, that he should forgive her mother. He reassures Pamina, that within these sacred halls revenge has no place.', 'die_zauberflöte/Mozart-Die_Zauberflöte-15-In_diesen_heilgen_Hallen.pdf', 'aria', 15, 71, 69, 10);
