INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (87, 'È strano... Ah fors''è lui che l''anima...', 'Violetta considers whether Alfredo could be her true love. She concludes that she needs to live her life in freedom, and that would make love hard.', 'la_traviata/Verdi-La_Traviata-7-È_strano..._Ah_fors''è_lui_che_l''anima....pdf', 'aria', 7, 88, 86, 11);
