INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (228, 'Questa o quella per me pari sono', 'The Duke lives a life where he enjoys the company of as many women as possible. He particularly enjoys sleeping with the women of married men.  ', 'rigoletto/Verdi-Rigoletto-3-Questa_o_quella_per_me_pari_sono.pdf', 'aria', 3, 229, 227, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (229, 'Partite, crudele', 'The Duke tells the Countess of Ceprano that she is a beautiful woman, and she should stay in his castle, instead of going back to her husband.', 'rigoletto/Verdi-Rigoletto-4-Partite,_crudele.pdf', 'terzetto', 4, 230, 228, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (230, 'Perigordino', 'This is a short dance piece. ', 'rigoletto/Verdi-Rigoletto-5-Perigordino.pdf', 'intermezzo', 5, 231, 229, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (231, 'Tutte è festa, tutta è gioia', 'Marullo informs the court that Rigoletto has a lover (This is not true, the woman believed to be his lover is in fact his daughter, Gilda). Rigoletto mocks the the Count of Ceprano and the courtiers for being cuckolds. Meanwhile the Duke is flirting with the Countess of Ceprano. The courtiers and the Count vows to have their revenge on Rigoletto for mocking them. ', 'rigoletto/Verdi-Rigoletto-6-Tutte_è_festa,_tutta_è_gioia.pdf', 'choir', 6, 232, 230, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (232, 'Oh tu che la festa audace hai turbato', 'Rigoletto mocks Count Monterone being cuckolded by the Duke. Monterone becomes furious and confronts the Duke. The Duke has Count Monterone arrested and put in jail, but before leaving the court, Count Monterone curses both the Duke and Rigoletto.', 'rigoletto/Verdi-Rigoletto-7-Oh_tu_che_la_festa_audace_hai_turbato.pdf', 'choir', 7, 233, 231, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (233, 'Qual vecchio maledivami', 'Rigoletto is thinking about the curse that Count Monterone put on him, when suddenly an assassin approaches him and offers Rigoletto his services. Rigoletto declines, but remembers the assassin and his offer. ', 'rigoletto/Verdi-Rigoletto-8-Qual_vecchio_maledivami.pdf', 'duet', 8, 234, 232, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (234, 'Pari siamo... Deh non parlare al misero', 'Rigoletto reflects over the similarities between himself, and the assassin Sparafucile. The assassin uses his sword to stab people and Rigoletto uses his tongue to metaphorically do the same. ', 'rigoletto/Verdi-Rigoletto-9-Pari_siamo..._Deh_non_parlare_al_misero.pdf', 'duet', 9, 235, 233, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (235, 'Signor nè principe io lo vorrei', '', 'rigoletto/Verdi-Rigoletto-10-Signor_nè_principe_io_lo_vorrei.pdf', 'duet', 10, 236, 234, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (236, 'Caro nome che il mio cor', '', 'rigoletto/Verdi-Rigoletto-11-Caro_nome_che_il_mio_cor.pdf', 'aria', 11, 237, 235, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (237, 'Zitti, zitti moviamo a vendetta', '', 'rigoletto/Verdi-Rigoletto-12-Zitti,_zitti_moviamo_a_vendetta.pdf', 'finale', 12, 238, 236, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (238, 'Ella mi fu rapita... Parmi veder le lagrime', 'The Duke is worried because Gilda seems to have disappeared. He thinks she is stolen from him.', 'rigoletto/Verdi-Rigoletto-13-Ella_mi_fu_rapita..._Parmi_veder_le_lagrime.pdf', 'aria', 13, 239, 237, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (239, 'Scorrendo uniti', 'The Duke''s servants enters, and tells the duke that they have captured Rigoletto''s mistress (though in fact she is his daughter). The Duke recognizes the captured woman as Gilda, and is overjoyous to have found her again.', 'rigoletto/Verdi-Rigoletto-14-Scorrendo_uniti.pdf', 'choir', 14, 240, 238, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (240, 'Possente amor mi chiama', 'The Duke is happy to have found Gilda again.', 'rigoletto/Verdi-Rigoletto-15-Possente_amor_mi_chiama.pdf', 'aria', 15, 241, 239, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (241, 'Povero Rigoletto... Cortigiani, vil razza dannata', '', 'rigoletto/Verdi-Rigoletto-16-Povero_Rigoletto..._Cortigiani,_vil_razza_dannata.pdf', 'aria', 16, 242, 240, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (242, 'Mio padre', '', 'rigoletto/Verdi-Rigoletto-17-Mio_padre.pdf', 'choir', 17, 243, 241, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (243, 'Tutte le feste al tempio... Si vendetta, tremenda vendetta', '', 'rigoletto/Verdi-Rigoletto-18-Tutte_le_feste_al_tempio..._Si_vendetta,_tremenda_vendetta.pdf', 'duet', 18, 244, 242, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (244, 'E l''ami... La donna è mobile', '', 'rigoletto/Verdi-Rigoletto-19-E_l''ami..._La_donna_è_mobile.pdf', 'aria', 19, 245, 243, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (245, 'Un di, se ben rammentomi... Bella figlia del''amore', '', 'rigoletto/Verdi-Rigoletto-20-Un_di,_se_ben_rammentomi..._Bella_figlia_del''amore.pdf', 'quartet', 20, 246, 244, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (246, 'M''odi... Ritorna a casa', '', 'rigoletto/Verdi-Rigoletto-21-M''odi..._Ritorna_a_casa.pdf', 'recitativo', 21, 247, 245, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (247, 'Ah più non ragiono... Somiglia un Apollo', '', 'rigoletto/Verdi-Rigoletto-22-Ah_più_non_ragiono..._Somiglia_un_Apollo.pdf', 'terzetto', 22, 248, 246, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (248, 'Della vendetta alfin giunge l''istante', '', 'rigoletto/Verdi-Rigoletto-23-Della_vendetta_alfin_giunge_l''istante.pdf', 'recitativo', 23, 249, 247, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (249, 'Chi è mai in sua vece... V''ho ingannato, colpevole fui', 'Rigoletto realizes that his assassin, Sparafucile, has not killed the Duke. He has instead kille Rigoletto''s daughter, Gilda. She sacrificed herself for the Duke, and shortly revives to sing the final duet of the Opera with her father, before dying.', 'rigoletto/Verdi-Rigoletto-24-Chi_è_mai_in_sua_vece.pdf', 'duet', 24, 272, 248, 16);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (250, 'Ouverture', 'The operetta starts with an ouverture', 'die_fledermaus/Strauss_II-Die_Fledermaus-1-Ouverture.pdf', 'ouverture', 1, 251, NULL, 17);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (251, 'Täubchen, das entflattert ist... Da schreibt meine Schwester Ida', 'Alfred sings a short aria, from outside the stage, trying to serenade Rosalinde. What he doesn''t know, is that Rosalinde isn''t the one listening, it is Adele. Adele then sings an aria and tells him off, while making a fool out of him', 'die_fledermaus/Strauss_II-Die_Fledermaus-2-Täubchen,_das_entflattert_ist..._Da_schreibt_meine_Schwester_Ida.pdf', 'aria', 2, 252, 250, 17);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (252, 'Ach, ich darf nicht hin zu dir', '', 'die_fledermaus/Strauss_II-Die_Fledermaus-3-Ach,_ich_darf_nicht_hin_zu_dir.pdf', 'duet', 3, 253, 251, 17);
