INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (304, 'Mario Cavaradossi... A voi', 'The jailor informs Cavaradossi that he has an hour left to live and offers to let him speak to a priest. Cavaradossi declines, and starts writing a letter to Tosca', 'tosca/Puccini-Tosca-29-Mario_Cavaradossi..._A_voi.pdf', 'recitativo', 29, 305, 303, 18);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (305, 'E lucevan le stelle', 'Knowing that he will soon die, Cavaradossi sings about his memories of Tosca. Life has never been been more precious to him than now.', 'tosca/Puccini-Tosca-30-E_lucevan_le_stelle.pdf', 'aria', 30, 306, 304, 18);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (306, 'Franchigia a Floria Tosca... O dolci mani... E non giungono... Come è lunga... Presto, su, Mario', 'The end of the opera, Mario Cavaradossi is executed, and Floria Tosca kills herself.', 'tosca/Puccini-Tosca-31-Franchigia_a_Floria_Tosca..._O_dolci_mani..._E_non_giungono..._Come_è_lunga..._Presto,_su,_Mario.pdf', 'finale', 31, 307, 305, 18);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (307, 'Tosca - Vocal Score', '', 'tosca/Puccini-Tosca-99-Tosca_-_Vocal_Score.pdf', 'score', 99, NULL, 306, 18);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (308, 'Prologue - Si puo', 'Tonio present the show', 'pagliacci/Leoncavallo-Pagliacci-1-Prologue_-_Si_puo.pdf', 'aria', 1, 309, NULL, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (309, 'Son qua', 'The people sees the commedia dell''arte troupe entering the village.', 'pagliacci/Leoncavallo-Pagliacci-2-Son_qua.pdf', 'choir', 2, 310, 308, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (310, 'Un tal gioco', 'Canio, who plays the role of Pagliacci, describes the show of the evening.', 'pagliacci/Leoncavallo-Pagliacci-3-Un_tal_gioco.pdf', 'aria', 3, 311, 309, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (311, 'I zampognari', '', 'pagliacci/Leoncavallo-Pagliacci-4-I_zampognari.pdf', 'choir', 4, 312, 310, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (312, 'Qual fiamma avea nel guardo... Stridono lassù', 'Canio frightens Nedda, but she is comforted by birdsong', 'pagliacci/Leoncavallo-Pagliacci-5-Qual_fiamma_avea_nel_guardo..._Stridono_lassù.pdf', 'aria', 5, 313, 311, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (313, 'Sei là... So ben che diforme', 'Tonio tells Nedda that he loves her, but she only laughs at him in return', 'pagliacci/Leoncavallo-Pagliacci-6-Sei_là..._So_ben_che_diforme.pdf', 'duet', 6, 315, 312, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (315, 'Silvio, a quest ora... Decidi il mio destin...', 'Nedda talks with her lover Silvio and they agree to elope, and that she will leave Canio. Tonio overhears them and decides to tell Canio.', 'pagliacci/Leoncavallo-Pagliacci-8-Silvio,_a_quest_ora..._Decidi_il_mio_destin....pdf', 'duet', 7, 316, 313, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (316, 'Aiutalo, Signor', 'Canio finds Silvio and Nedda together, but Silvio manages to escape before Canio sees who he is. Canio threatens Nedda with a knife and wants her to tell him who the lover is. Beppe disarms Canio, and tells them they have a show to do.', 'pagliacci/Leoncavallo-Pagliacci-8-Aiutalo,_Signor.pdf', 'quartet', 8, 317, 315, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (317, 'Vesti la giubba', 'Canio is heartbroken, and alone. He dresses up for the show tonight, and prepares himself to laugh.', 'pagliacci/Leoncavallo-Pagliacci-9-Vesti_la_giubba.pdf', 'aria', 9, 318, 316, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (318, 'Intermezzo', '', 'pagliacci/Leoncavallo-Pagliacci-10-Intermezzo.pdf', 'intermezzo', 10, 319, 317, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (319, 'Presto affrettiamoci', '', 'pagliacci/Leoncavallo-Pagliacci-11-Presto_affrettiamoci.pdf', 'choir', 11, 320, 318, 19);
