INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (321, 'O Colombina, il tenero fido Arlecchin è a te vicin', '', 'pagliacci/Leoncavallo-Pagliacci-13-O_Colombina,_il_tenero_fido_Arlecchin_è_a_te_vicin.pdf', 'aria', 13, 322, 320, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (322, 'È dessa... Dei, come è bella', '', 'pagliacci/Leoncavallo-Pagliacci-14-È_dessa..._Dei,_come_è_bella.pdf', 'aria', 14, 323, 321, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (323, 'Arlecchin... Columbina... Alfin s''arrenda', '', 'pagliacci/Leoncavallo-Pagliacci-15-Arlecchin..._Columbina..._Alfin_s''arrenda.pdf', 'aria', 15, 324, 322, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (324, 'Nome di Dio, quelle stesse parole... No, Pagliaccio non son', 'Canio hears Nedda saying the same words, that she told Silvio in the first act. He becomes furious and demands to know the lover''s name. She refuses, and tries to remind him they are still in a play. Canio doesn''t listen but becomes even more angry. He then stabs Nedda, and she dies. Silvio tries to protect her but also he gets murdered by the furious Canio. The opera ends with the words, the comedy is over.', 'pagliacci/Leoncavallo-Pagliacci-16-Nome_di_Dio,_quelle_stesse_parole..._No,_Pagliaccio_non_son.pdf', 'finale', 16, 325, 323, 19);
INSERT INTO pieces (id, title, description, file_title, type, placement, next_id, prev_id, opera_id) VALUES (325, 'Pagliacci - Vocal score', '', 'pagliacci/Leoncavallo-Pagliacci-99-Pagliacci_-_Vocal_score.pdf', 'score', 99, NULL, 324, 19);
